// ER ENTITY: STUDENT
// Attributes: StudentID (PK, Simple), Name (Simple), Address (Composite), Phone (Multi-valued), Age (Derived)

CREATE TABLE Student (
    StudentID INT PRIMARY KEY,
    Name VARCHAR(50) NOT NULL,
    Street VARCHAR(50),
    City VARCHAR(30),
    State VARCHAR(30),
    PinCode VARCHAR(10),
    DateOfBirth DATE NOT NULL
);

// Multi-valued attribute Phone becomes separate table
CREATE TABLE StudentPhone (
    StudentID INT,
    PhoneNumber VARCHAR(15),
    PRIMARY KEY (StudentID, PhoneNumber),
    FOREIGN KEY (StudentID) REFERENCES Student(StudentID)
);

// Note: Derived attribute Age NOT stored - computed from DateOfBirth

// ER: EMPLOYEE (Strong) -> Has -> DEPENDENT (Weak)
// Employee: EmployeeID (PK), Name, Department
// Dependent: DependentName (Partial Key), Relationship

CREATE TABLE Employee (
    EmployeeID INT PRIMARY KEY,
    EmpName VARCHAR(50) NOT NULL,
    Department VARCHAR(30)
);

CREATE TABLE Dependent (
    EmployeeID INT,
    DependentName VARCHAR(50),
    Relationship VARCHAR(20),
    PRIMARY KEY (EmployeeID, DependentName),
    FOREIGN KEY (EmployeeID) REFERENCES Employee(EmployeeID)
        ON DELETE CASCADE
);

// The primary key of Dependent is (EmployeeID + DependentName)
// Foreign key also serves as primary key (composite)
// ON DELETE CASCADE ensures dependent deleted when employee deleted

// CASE 1: 1:1 Relationship - Department has one Manager (Employee)
CREATE TABLE Department (
    DeptID INT PRIMARY KEY,
    DeptName VARCHAR(30),
    ManagerID INT UNIQUE,  // UNIQUE ensures 1:1
    FOREIGN KEY (ManagerID) REFERENCES Employee(EmployeeID)
);

// CASE 2: 1:N Relationship - Department has many Employees
CREATE TABLE Employee (
    EmployeeID INT PRIMARY KEY,
    EmpName VARCHAR(50),
    DeptID INT,  // Foreign key in 'many' side
    FOREIGN KEY (DeptID) REFERENCES Department(DeptID)
);

// CASE 3: M:N Relationship - Student enrolls in Courses
CREATE TABLE Student (
    StudentID INT PRIMARY KEY,
    Name VARCHAR(50)
);

CREATE TABLE Course (
    CourseID INT PRIMARY KEY,
    CourseName VARCHAR(30)
);

// Junction table for M:N (includes relationship attributes)
CREATE TABLE Enrollment (
    StudentID INT,
    CourseID INT,
    EnrollmentDate DATE,
    Grade CHAR(2),
    PRIMARY KEY (StudentID, CourseID),
    FOREIGN KEY (StudentID) REFERENCES Student(StudentID),
    FOREIGN KEY (CourseID) REFERENCES Course(CourseID)
);

class Entity:
    def __init__(self, name, attributes, key_attributes):
        self.name = name
        self.attributes = attributes  # List of attribute names
        self.key_attributes = key_attributes  # Primary key attributes

    def is_valid_entity(self):
        """Check if entity has at least one attribute and a key"""
        if not self.attributes:
            return False, "Entity must have at least one attribute"
        if not self.key_attributes:
            return False, "Entity must have a primary key"
        for key in self.key_attributes:
            if key not in self.attributes:
                return False, f"Key {key} not in attributes"
        return True, "Valid entity"

class Relationship:
    def __init__(self, name, entities, cardinality):
        self.name = name
        self.entities = entities  # List of participating entities
        self.cardinality = cardinality  # '1:1', '1:N', 'M:N'

    def validate_cardinality(self):
        """Validate cardinality format"""
        valid = ['1:1', '1:N', 'N:1', 'M:N']
        if self.cardinality not in valid:
            return False, f"Invalid cardinality. Use: {valid}"
        return True, "Valid cardinality"

# Example usage
student = Entity("Student", ["StudentID", "Name", "Age"], ["StudentID"])
valid, msg = student.is_valid_entity()
print(f"Entity validation: {msg}")

enroll = Relationship("Enrolls", ["Student", "Course"], "M:N")
valid, msg = enroll.validate_cardinality()
print(f"Relationship validation: {msg}")
